/* Define a variable font */
@font-face {
  font-family: 'Inter Variable';
  src: url('/fonts/Inter-roman.var.woff2') format('woff2-variations');
  font-weight: 100 900; /* Define the weight range */
  font-display: swap;
}

body {
  font-family: 'Inter Variable', sans-serif;
  font-weight: 450; /* Use an intermediate weight */
}

h1 {
  /* Apply specific variation settings for weight and optical size */
  font-variation-settings: 'wght' 700, 'opsz' 36;
  letter-spacing: -0.02em;
}

.fine-tuned-text {
  /* Adjust slant and width for specific elements */
  font-variation-settings: 'slnt' -10, 'wdth' 95;
}

@font-face {
  font-family: 'Inter Bold';
  src: url('/fonts/Inter-Bold.woff2') format('woff2'),
       url('/fonts/Inter-Bold.woff') format('woff');
  font-weight: 700;
  font-style: normal;
  font-display: swap; /* Ensures immediate fallback rendering */
}

body {
  font-family: 'Inter Bold', Helvetica, Arial, sans-serif;
  line-height: 1.6;
  color: #333;
}

/* For general text, prioritizing content visibility */
@font-face {
  font-family: 'Inter Sans';
  src: url('/fonts/Inter-Regular.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Provides a fallback font immediately, swaps when web font loads */
}

/* For brand-critical headlines, prioritizing font aesthetic but with a short block period */
@font-face {
  font-family: 'Brand Display';
  src: url('/fonts/BrandDisplay-Bold.woff2') format('woff2');
  font-weight: 700;
  font-style: normal;
  font-display: fallback; /* Short block, then swap if not loaded; avoids extreme FOUT */
}

/* For non-essential fonts (e.g., specific icons), prioritizing no layout shift */
@font-face {
  font-family: 'Icon Set';
  src: url('/fonts/IconSet.woff2') format('woff2');
  font-weight: normal;
  font-style: normal;
  font-display: optional; /* Uses the font only if it's available without causing a layout shift */
}

h2 {
  /* 
   * CSS clamp() provides a fluid range:
   * 1.5rem = minimum font size (e.g., on small mobile screens)
   * 3vw + 1rem = preferred fluid size (scales with viewport width)
   * 3.5rem = maximum font size (e.g., on very large desktop screens)
   */
  font-size: clamp(1.5rem, 3vw + 1rem, 3.5rem);
  line-height: 1.2;
  font-family: 'Inter', sans-serif; /* Example web font for modern UI */
  margin-bottom: 0.8em;
}

/* 1. Optimize Web Font Loading with font-display */
@font-face {
  font-family: 'Inter-Regular';
  src: url('/fonts/Inter-Regular.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Critical for perceived performance and UX */
}

/* 2. Implement Fluid Typography with clamp() for Responsive Sizing */
body {
  font-family: 'Inter-Regular', sans-serif;
  /* clamp(minimum, preferred, maximum) */
  /* Example: Font size fluidly scales between 1rem (16px) and 1.25rem (20px) */
  font-size: clamp(1rem, 2vw + 0.5rem, 1.25rem);
  line-height: 1.6;
  color: #2c3e50;
}

h1 {
  /* Example: Heading size fluidly scales between 2rem (32px) and 3.5rem (56px) */
  font-size: clamp(2rem, 5vw + 1rem, 3.5rem);
  line-height: 1.15;
  margin-bottom: 0.75em;
}

